    position: fixed;
    top: 0;
    left: 0;
    bottom:0;
    right:0;
    z-index: 0;
    margin-left: 0px;
    background-color: gray;
    transition: margin-left .4s cubic-bezier(0.25, .8, .25, 1);
    touch-action: none;
    -ms-touch-action: none;
    overscroll-behavior: none;
}

.map-view #map .mapboxgl-canvas {
    touch-action: none;
    -ms-touch-action: none;
}

.map-view .sideBarActive{

      margin-left: 300px !important;
      transition: margin-left .4s cubic-bezier(0.25, .8, .25, 1);

}

