  height: 0px;
  width: 100%;
  background-color: gray;
  overflow: auto;
  position: relative;
  margin-top: 10px;
  box-shadow: 0 0 10px rgba(0,0,0, 0.25);
  transition: height .8s cubic-bezier(0.25, .8, .25, 1);
}

.activeMap{
  height: 150px;
  transition: height .8s cubic-bezier(0.25, .8, .25, 1);
}

#favMap{
  height: 150px !important;
  width: 100% !important;
  position: relative;
}


.favorites {
  position: relative;
  height: calc(100% - 35px);
}

.favListContainer{
  height: calc(100% - 207px);
  overflow: auto;
}


.fa-times {
  cursor: pointer;
}

.favorites .delete i{
  position: relative;
  right: -4px;
  top: -30px
}


.favorites i {
  float: right;
  position: relative;
  padding: 4px;
  top: 34px;
  right: 25px;
  opacity: 0.4;
}

.favorites ul {
  position: relative;
  padding: 0;
  margin-top: 8px;
  min-width: 100%;
  background-color: #fff;
  list-style: none;
  border-radius: 4px;
  box-shadow: 0 0 10px rgba(0,0,0, 0.25);
  z-index: 1000;
}

.favorites li {
  padding: 10px 16px;
  border-bottom: 1px solid #ccc;
  cursor: pointer;
}

.favorites li:first-child {
  border-radius: 4px 4px 0 0;
}

.favorites li:last-child {
  border-radius: 0 0 4px 4px;
  border-bottom: 0;
}

.favorites span {
  display: block;
  color: #2c3e50;
}

.favorites .active {
  background-color: #4fc08d;
}

.favorites .active span {
  color: white;
}

.favorites .name {
  font-weight: 700;
  font-size: 18px;
}

.favorites .screen-name {
  font-style: italic;
}

.favorites .close-name {
  margin-top: 10px;
}


.textContainer{
  height: 36px;
}

.previousPlaceText{
  padding: 5px;
  float: left;
  color: #000 !important;
}

.clearAll{
  float: right;
  padding: 5px;
    color: #fff !important;

}

.delete{
  /*position: absolute;*/
  right: 5px;
  top: 20px;
}












