  position: relative;
  top: 0;
  width: 100%;
  bottom: 0px;
  /*background-color: gray;*/
}

.home .header{
  position: relative;
  margin: 0 auto;
  display: table;
  text-align: center;
}

.home a {
  font-size: 16px;
  overflow: hidden;
  display: inline-block;
  margin-bottom: 8px;
  width: calc(50% - 4px);
  margin-right: 8px;
  height: 150px;
  cursor: pointer;
  position: relative;
}

.home a:nth-of-type(2n) {
  margin-right: 0;
}

@media screen and (min-width: 50em) {
  .home a {
    width: calc(25% - 6px);
  }
  
  .home a:nth-of-type(2n) {
    margin-right: 8px;
  }
  
  .home a:nth-of-type(4n) {
    margin-right: 0;
  }
}

.home a:hover img {
  transform: scale(1.15);
  /*-webkit-filter: blur(5px);
  filter: blur(5px);*/
}

.home figure {
  margin: 0;
  position: relative;
}

.home img {
  border: none;
  width: 100%;
  height: 200px;
  display: block;
  background: #ccc;
  transition: transform .2s ease-in-out;
  filter: brightness(70%);
  -webkit-filter: brightness(70%);
}

.home .p a {
  display: inline;
  font-size: 13px;
  margin: 0;
}

.home .p {
  text-align: center;
  font-size: 13px;
  padding-top: 100px;
}

.home .cityName{
  position: absolute;
    width: 100%;
    z-index: 100;
    color: #fff;
    text-align: center;
    font-size: 16px;
    margin-top: 10px;
}

.home .rig-text {
    display:block;
    padding:0 30px;
    box-sizing:border-box;
    position:absolute;
    left:0;
    width:100%;
    text-align:center;
    text-transform:capitalize;
    font-size:24px;
    font-weight:bold;
    font-weight:normal!important;
    top:40%;
    color:white;
    opacity:0;
    filter:alpha(opacity=0);/*For older IE*/
    transform:translateY(-20px);
    transition:all .3s;
    z-index: 100;
}

.spinnerHome {
  width: 40px;
  height: 40px;
  position: absolute;
  margin: auto;
  top: 125%;
  left: 50%;
  /* bring your own prefixes */
    transform: translate(-50%, -50%);
    z-index: 100;
}

.double-bounce1, .double-bounce2 {
  width: 100%;
  height: 100%;
  border-radius: 50%;
  background-color: #4fc08d;
  opacity: 1;
  position: absolute;
  top: 0;
  left: 0;
  animation: sk-bounce 2.0s infinite ease-in-out;
}

.double-bounce2 {
  animation-delay: -1.0s;
}

@keyframes sk-bounce {
  0%, 100% { 
    transform: scale(0.0);
    -webkit-transform: scale(0.0);
  } 50% { 
    transform: scale(1.0);
    -webkit-transform: scale(1.0);
  }
}













