body,
#app {
  width: 100%;
  height: 100%;
  overflow: hidden;
}

body{
  font-family: 'Raleway';
  margin: 0;
  padding: 0;
  overscroll-behavior: none;
}

.homeContainer{
  top:0;
  bottom: 0;
  right:0;
  left: 0;
  position: absolute;
  z-index: 100;
  padding: 20px;
  overflow: auto;

}

.searchingContainer{

	top:0;
	bottom: 0;
	right:0;
	left: 0;
	position: absolute;
	/*background-color: gray;*/
	z-index: 100;
	padding: 20px;

}

.fade-transition {
  transition: opacity 0.4s ease;
}
.fade-enter, .fade-leave {
  opacity: 0;
}

.favoritesContainer{
  top:0;
  bottom: 0;
  right:0;
  left: 0;
  position: absolute;
  /*background-color: #fff;*/
  z-index: 100;
  padding: 20px;
  /*overflow: auto;*/
}

.ui-preloader-progressbar::before, .ui-preloader-progressbar::after {
    display: block;
    position: absolute;
    top: 0;
    z-index: 1;
    width: 0;
    height: 10px;
    background: #afa;
    animation: ui-preloader-front linear 3s infinite;
    content: '';
}
.shareContainer{
  top:0;
  bottom: 0;
  right:0;
  left: 0;
  position: absolute;
  /*background-color: gray;*/
  z-index: 100;
  padding: 20px;
  /*overflow: auto;*/
}

.modalContainer{

  top:0;
  bottom: 0;
  right:0;
  left: 0;
  position: absolute;
  background-color: #ffffff;
  /*background-color: rgba(0,0,0,0.3);*/
  z-index: 100;
  padding: 20px;
  overflow: auto;
  /*color: #ffffff;*/
}

@media (min-width: 767px) {

  .searchingContainer{
    right: 80px;
    left: 80px;
  }
  .favoritesContainer{
    right: 80px;
    left: 80px;
  }
  .shareContainer{
    right: 80px;
    left: 80px;
  }
  /*.modalContainer{
    right: 80px;
    left: 80px;
  }*/
  .homeContainer{
    right: 80px;
    left: 80px;
  }
  
}

@media (min-width: 1023px) {

  .searchingContainer{
    right: 220px;
    left: 220px;
  }
  .favoritesContainer{
    right: 220px;
    left: 220px;
  }
  .shareContainer{
    right: 220px;
    left: 220px;
  }
  .homeContainer{
    right: 220px;
    left: 220px;
  }
  
}





.directionContainer{


  top:0;
  bottom: 0;
  right:0;
  left: 0;
  position: absolute;
  /*background-color: gray;*/
  z-index: 100;

}

.closeContainer{
	height: 35px;
      /*margin-top: 10px;*/
}

.modalClose {
    height: 25px;
    margin-top: 14px;
    width: 25px;
    position: relative;
    /*top: 50%;
    right: 0;*/
    float: right;
    transform: translate(0, -50%);
    z-index:9999999999;
}
.modalClose:hover {
    cursor: pointer;
}
.modalClose:hover span {
    /*background-color: black;*/
}
.modalClose span {
    position: absolute;
    Z-index: 1;
    width: 2px;
    height: 28px;
    top: -1px;
    margin-left: 12px;
    background-color: black;
    transition: all .12s linear;
    display: block;
}
.modalClose span:first-child {
    transform: rotate(45deg);
}
.modalClose span:last-child {
    transform: rotate(135deg);
}
.mapboxgl-ctrl-bottom-right {
    right: 0;
    bottom: 0;
    display: none;
}

.searchButton{
  position: absolute;
  top: 20px;
  right: 20px;
  z-index: 100;
  border-radius: 50%;
  width: 35px;
  height: 35px;
  /*background-color: #000; */
  background-color:rgba(192,192,192,0.3);
  border: 1px solid #fff;  
}
.searchButton i {
    left: 9px;
    position: absolute;
    font-size: 20px;
    top: 8px;
    color: #fff;
}
.searchButton button{
  background-color: #4fc08d !important;
}


.progress{
  top: 0px;
  z-index: 1;
  position: absolute;
}




