  font-size: 16px;
  text-align: center;
  width: 170px;
  margin: auto;
  position: relative;
  color: #fff;
}
.imgSpinner{
  position: absolute;
  z-index: 10;
  top: 48%;
  left: 47%;
}
.chevron{
  position: absolute;
  z-index: 10;
  top: 50%;
  color: #fff;
  font-size: 25px;
  text-shadow: 1px 2px 3px #666;
}
.prev{
  left: 10px;
}
.next{
  right: 10px; 
}




