  padding: 1rem 2rem;
  opacity: 0;
  background-color: #fff;
  max-width: 640px;
  margin: 0 auto;
  top:0px;
  bottom: 0px;
}
.modal-full-wrapper img{
  margin-top: 20px;
  margin-top: 20px;
  max-width: 400px;
  display: block; 
  margin-left: auto;
  margin-right: auto;
}





.modal-full-wrapper .full img{
  width: 100%
}

.modal-full-wrapper p{
    background: #fff;
    padding: 17px;
}

.modal-full-wrapper i{
    cursor: pointer;
}



.modal-full-header .header {
  padding: 20px 0px 20px 0px;
  position: relative;
  text-align: center;
}

.header {
    padding: 20px 0px 0px 0px
}

.header h3 {
  text-align: center;
  font-size: 20px;
  padding: 0px 50px;
}

.fullres{
  text-align: center;
  margin-top: 10px;
}

.hearColor{
  color: #4fc08d;
}

.appear{
  opacity: 1;
    /*@include transition (all 0.4s linear);
    /*transition: 0.4s -webkit-filter linear;*/
    transition: 0.4s opacity linear;
    -webkit-transition: 0.4s -webkit-opacity linear;
    -moz-transition: 0.4s -moz-opacity linear;
    -ms-transition: 0.4s -ms-opacity linear;
    -o-transition: 0.4s -o-opacity linear;
}

.clippyImage{
  height: 19px;
  margin-top: 0px !important;
  cursor: pointer;
}

#foo{
    width: 100%;
  }



 .modal-full-wrapper input {
    /*width: 100%;*/
    height: 20px;
    font-size: 16px;
    color: #2c3e50;
    line-height: 0.428571;
    box-shadow: inset 0 1px 4px rgba(0,0,0,.4);
    -webkit-gitbox-shadow: inset 0 1px 4px rgba(0,0,0,.4);
    transition: border-color ease-in-out .15s,box-shadow ease-in-out .15s;
    font-weight: 300;
    padding: 14px 11px;
    border: none;
    border-radius: 6px;
    -webkit-border-radius: 6px;
    letter-spacing: 1px;
    box-sizing: border-box;
    top: -3px;
    position: relative;
}

.modal-full-wrapper button {

  width: 32px;
  margin-left: 46.5%;
  margin-bottom: 6px;
}


@media (max-width: 500px ) {
  .header {
    padding: 20px 0px 0px 0px;
  }
  .modal-full-wrapper{
    padding: 0px;
  }

  .modal-full-wrapper img{
    margin-top: 20px;
    margin-top: 20px;
    width: 100%;
    display: block; 
    margin-left: auto;
    margin-right: auto;
  }

  /*#foo{
    width: 100%
  }*/

}

.gallery{
  position: absolute;
  top: 10px;
  left: 10px;
  z-index: 10;
  font-size: 30px;
}

.gallery i{
  color: #fff;
  text-shadow: 1px 2px 3px #666;
}

.groupPager {
  position: absolute;
  top: 50%;
  z-index: 11;
  width: 38px !important;
  height: 38px;
  margin: 0 !important;
  border: 1px solid rgba(255,255,255,0.8);
  border-radius: 50%;
  background-color: rgba(0,0,0,0.35);
  color: #fff;
  transform: translateY(-50%);
}

.groupPagerPrev {
  left: 10px;
}

.groupPagerNext {
  right: 10px;
}

.groupCounter {
  position: absolute;
  right: 14px;
  bottom: 12px;
  z-index: 11;
  padding: 4px 8px;
  border-radius: 10px;
  background-color: rgba(0,0,0,0.45);
  color: #fff;
  font-size: 12px;
}









