  transition: opacity 0.4s ease;
}
.fade-enter, .fade-leave {
  opacity: 0;
}

.distIndicator{
  left: 0px;
}

.count{
  /*color: gray;*/
  font-size: 12px;
}

.dirIndicator{
  position: absolute;
  right: 0px;
  margin-right: 35px;
  color: #4fc08d;
}

.mobile-list-view{
      bottom: -104px;
      position: fixed;
      right: 0;
      left: 0;
      z-index: 100;
      transition: bottom .4s cubic-bezier(0.25, .8, .25, 1);
      overflow-x: auto;
      overflow-y: hidden;
      -webkit-overflow-scrolling: touch;
      touch-action: pan-x;
      -ms-touch-action: pan-x;
      height: 159px;
      display: -ms-flexbox;
      display: flex;
      -ms-flex-wrap: nowrap;
          flex-wrap: nowrap;
    }

  @media screen and (min-width: 767px) {

      .mobile-list-view {
          /*width: 768px;*/
          margin: auto;
        }

    }

::-webkit-scrollbar { 
  display: none; 
}
/* optional: show position indicator in red */
::-webkit-scrollbar-thumb {
    background: #FF0000;
}


    .active{
      bottom: 5px;
      transition: bottom .4s cubic-bezier(0.25, .8, .25, 1);
    } 

.image.is-64x64 {
    margin: auto;
}

.card{
  margin: 0px 10px;
  -ms-flex: 0 0 calc(100vw - 40px);
      flex: 0 0 calc(100vw - 40px);
  max-width: 440px;
  position: relative;
  border-radius: 10px;
  border: 2px solid rgba(79, 192, 141, 0.0);
  height: 150px;
  opacity: 0.8;
  -ms-touch-action: pan-x;
      touch-action: pan-x;
}

.image img {
    display: block;
    height: 64px;
    margin: auto;   
}
.card-image{
  height: 70px;
  border-top-right-radius: 10px;
  border-top-left-radius: 10px;
  background-position: 50% 50% !important;
}
.card-content{
  /*background-color: #fff;*/
  padding: 10px;
}

.card .media{
  white-space: nowrap;
    overflow: hidden;
    -webkit-line-clamp: 1;
    text-overflow: ellipsis;
}

.activeMobile{
  border: 2px solid rgba(79, 192, 141, 1);
  color: #fff !important;
  background-color: #a7dfc6;
  opacity: 1;
  /*overflow: auto;*/
}

.locateMe{
  position: absolute;
  bottom: 170px;
  right: 19px;
  z-index: 100;
  border-radius: 50%;
  width: 40px;
  height: 40px;
  background-color:rgba(192,192,192,0.3); 
  z-index: 200;
  
}
.locateMe i {
    left: 11px;
    position: absolute;
    font-size: 20px;
    top: 10px;
    color: #fff;
}
.locateMe button{
  background-color: #4fc08d !important;
}

.activeLocation{
  color: #009ACD !important;
}

.desktopViewButton{
  position: absolute;
    right: 10px;
    top: 10px;
    color: #fff;
    z-index: 1;
    font-size: 20px;
    cursor: pointer;
    text-shadow: 1px 2px 3px #666;
}

.groupBadge{
  position: absolute;
  left: 10px;
  top: 10px;
  z-index: 2;
  min-width: 38px;
  height: 24px;
  padding: 0 8px;
  border-radius: 12px;
  background-color: rgba(79, 192, 141, 0.95);
  color: #fff;
  font-size: 13px;
  line-height: 24px;
