  min-width: 100%;
  background-color: #fff;
  list-style: none;
  border-radius: 4px;
  box-shadow: 0 0 10px rgba(0,0,0, 0.25);
  z-index: 1000;
}

.typeahead li {
  padding: 10px 16px;
  border-bottom: 1px solid #ccc;
