   width: 100%;
   height: 100%;
   position: relative;
 }
 
 #miniMap{
   position: relative;
   /*height: 100px !important;
   width: 100% !important;*/
   opacity: 0;
 }

 .showMap{
   opacity: 1 !important;
 }



 .whiteMask {

   height: 80px;
   width: 100%;
   position: absolute;
   bottom:0px;
   z-index: 1;
   background: rgba(255,255,255,0); /* For browsers that do not support gradients */ /*Safari 5.1-6*/ /*Opera 11.1-12*/ /*Fx 3.6-15*/
   background: linear-gradient(top, rgba(255,255,255,0), rgba(255,255,255,1)); /*Standard*/

 }

 .imagePointer{
   position: absolute;
   top: 0px;
   left: 49.7%;
   background-color: #4fc08d;
   width: 2px;
   z-index: 1;
   left: 49.8%;
   height: 0px;
   transition: height 1s;
 }

.orale {
   height: 67px;
 }




