  position: relative;
  height: calc(100% - 35px);
}

.shareListContainer{
  height: calc(100% - 207px);
  overflow: auto;
  width: 100%;
}


.fa-times {
  cursor: pointer;
}

.share .delete i{
  position: relative;
  right: -4px;
  top: -30px
}


.share i {
  margin-right: 15px;
}

.share ul {
  position: relative;
  padding: 0;
  margin-top: 8px;
  min-width: 100%;
  background-color: #fff;
  list-style: none;
  border-radius: 4px;
  box-shadow: 0 0 10px rgba(0,0,0, 0.25);
  z-index: 1000;
}

.share li {
  padding: 20px 26px;
  border-bottom: 1px solid #ccc;
  cursor: pointer;
}

.share li:first-child {
  border-radius: 4px 4px 0 0;
}

.share li:last-child {
  border-radius: 0 0 4px 4px;
  border-bottom: 0;
}

.share span {
  display: block;
  color: #2c3e50;
}

.share .active {
  background-color: #4fc08d;
}

.share .active span {
  color: white;
}

.share .name {
  font-weight: 700;
  font-size: 18px;
}

.share .screen-name {
  font-style: italic;
}

.textContainer{
  height: 36px;
}

.previousPlaceText{
  padding: 5px;
  float: left;
  color: #fff !important;
}

.clearAll{
  float: right;
  padding: 5px;
}












